create table if not exists clientes (id uuid primary key default gen_random_uuid(), nome text, nif text, telefone text, email text, morada text, created_at timestamptz default now());
create table if not exists obras (id uuid primary key default gen_random_uuid(), cliente_id uuid references clientes(id), morada text, estado text, valor numeric, created_at timestamptz default now());
create table if not exists orcamentos (id uuid primary key default gen_random_uuid(), obra_id uuid references obras(id), numero text, mao_obra numeric, materiais numeric, total numeric, estado text, created_at timestamptz default now());
